const h = JSON.parse(require('fs').readFileSync('/tmp/health.json','utf8'));
const o = JSON.parse(require('fs').readFileSync('/tmp/other.json','utf8'));
console.log('healthcare:', h.passed+'/'+h.total, 'failed:', h.failedCount);
